-- Migración: Actualizar plantilla fin_proceso_general para soporte de múltiples roles

-- Actualizar plantilla para usar variable {cargo_rol} en lugar de texto hardcodeado
UPDATE `plantillas_correo` SET 
  cuerpo = '<h2>Estimado/a {nombre_director},<br>{cargo_rol}{direcciones_director}</h2>\n\n<p>Por medio del presente, le informamos que el día de hoy, <strong>{fecha_cierre}</strong>, correspondiente al <strong>10° día hábil del mes</strong>, se ha dado por <strong>finalizado el proceso de carga de información</strong> en el Portal de Transparencia Activa para el período <strong>{mes_carga} {ano_carga}</strong>, conforme a los plazos establecidos por la Ley N° 20.285 sobre Acceso a la Información Pública.</p>\n\n<h3>⚠️ Importante:</h3>\n<p>A partir de esta fecha, toda información que <strong>no haya sido cargada oportunamente</strong> en el portal se considera fuera de plazo. El incumplimiento en la entrega oportuna de la información de Transparencia Activa podría constituir una <strong>infracción a la Ley de Transparencia</strong>, susceptible de ser sancionada por el Consejo para la Transparencia conforme a los artículos 45 y siguientes de la referida ley.</p>\n\n<p>Si existen documentos pendientes de carga correspondientes a este período, le solicitamos que sean <strong>ingresados a la brevedad posible</strong> para regularizar la situación y minimizar eventuales riesgos de incumplimiento normativo.</p>\n\n<h3>Resumen - Período {mes_carga} {ano_carga}:</h3>\n{resumen_general}\n\n<p>Puede consultar el resumen completo de todos los ítems del municipio en el siguiente enlace:</p>\n<p style=\"text-align:center;\"><a href=\"{enlace_resumen}\" style=\"display:inline-block; padding:12px 24px; background-color:#0d6efd; color:#ffffff; text-decoration:none; border-radius:5px; font-weight:bold;\">📊 Ver Resumen Municipal Completo</a></p>\n\n<p>Saludos cordiales,<br>\n<strong>Municipalidad de Los Lagos</strong><br>\nUnidad de Transparencia</p>',
  variables_disponibles = '{"nombre_director": "Nombre completo del destinatario", "cargo_rol": "Cargo del destinatario (Director/a de, Auditor/a - )", "direcciones_director": "Nombre(s) de la(s) dirección(es) o ámbito de responsabilidad", "mes_carga": "Nombre del mes", "ano_carga": "Año", "fecha_cierre": "Fecha del cierre (10° día hábil)", "resumen_general": "Tabla resumen de ítems", "enlace_resumen": "URL pública al resumen municipal completo"}'
WHERE tipo = 'fin_proceso_general';
